import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  X, RotateCcw, Undo2, Swords, Trophy, 
  Volume2, VolumeX, Cpu, History, User, Loader2
} from 'lucide-react';

// 声明全局 Chess 对象
declare var Chess: any;

const PIECE_IMAGES: Record<string, string> = {
  wP: 'https://upload.wikimedia.org/wikipedia/commons/4/45/Chess_plt45.svg',
  wN: 'https://upload.wikimedia.org/wikipedia/commons/7/70/Chess_nlt45.svg',
  wB: 'https://upload.wikimedia.org/wikipedia/commons/b/b1/Chess_blt45.svg',
  wR: 'https://upload.wikimedia.org/wikipedia/commons/7/72/Chess_rlt45.svg',
  wQ: 'https://upload.wikimedia.org/wikipedia/commons/1/15/Chess_qlt45.svg',
  wK: 'https://upload.wikimedia.org/wikipedia/commons/4/42/Chess_klt45.svg',
  bP: 'https://upload.wikimedia.org/wikipedia/commons/c/c7/Chess_pdt45.svg',
  bN: 'https://upload.wikimedia.org/wikipedia/commons/e/ef/Chess_ndt45.svg',
  bB: 'https://upload.wikimedia.org/wikipedia/commons/9/98/Chess_bdt45.svg',
  bR: 'https://upload.wikimedia.org/wikipedia/commons/f/ff/Chess_rdt45.svg',
  bQ: 'https://upload.wikimedia.org/wikipedia/commons/4/47/Chess_qdt45.svg',
  bK: 'https://upload.wikimedia.org/wikipedia/commons/f/f0/Chess_kdt45.svg',
};

const PIECE_VALUES: Record<string, number> = { p: 1, n: 3, b: 3, r: 5, q: 9, k: 0 };

type BoardTheme = 'wood' | 'green' | 'blue';

const THEMES: Record<BoardTheme, { light: string, dark: string, name: string }> = {
  wood: { light: '#f0d9b5', dark: '#b58863', name: '经典木纹' },
  green: { light: '#eeeed2', dark: '#769656', name: '森林绿' },
  blue: { light: '#dee3e6', dark: '#8ca2ad', name: '赛博蓝' }
};

const ChessApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [game, setGame] = useState<any>(null);
  const [board, setBoard] = useState<any[][]>([]);
  const [selectedSquare, setSelectedSquare] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<string[]>([]);
  const [history, setHistory] = useState<string[]>([]);
  const [status, setStatus] = useState<string>('白方走棋');
  const [gameOver, setGameOver] = useState<boolean>(false);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [theme, setTheme] = useState<BoardTheme>('green');
  const [lastMove, setLastMove] = useState<{ from: string, to: string } | null>(null);
  const [isLibReady, setIsLibReady] = useState(false);

  const [evalValue, setEvalValue] = useState<number>(0);
  const [whiteTimer, setWhiteTimer] = useState(600);
  const [blackTimer, setBlackTimer] = useState(600);
  const [captured, setCaptured] = useState<{ w: string[], b: string[] }>({ w: [], b: [] });
  const [materialAdv, setMaterialAdv] = useState(0);

  const audioCtx = useRef<AudioContext | null>(null);
  const timerRef = useRef<any>(null);

  const playSound = useCallback((type: 'move' | 'capture' | 'check' | 'checkmate') => {
    if (!soundEnabled) return;
    if (!audioCtx.current) audioCtx.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    const ctx = audioCtx.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    if (type === 'move') {
      osc.frequency.setValueAtTime(200, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.1);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
    } else if (type === 'capture') {
      osc.type = 'square';
      osc.frequency.setValueAtTime(150, ctx.currentTime);
      gain.gain.setValueAtTime(0.05, ctx.currentTime);
    } else if (type === 'check') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(440, ctx.currentTime);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
    }
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(); osc.stop(ctx.currentTime + 0.1);
  }, [soundEnabled]);

  const runEvaluation = (gameObj: any) => {
    if (!gameObj) return;
    const currentBoard = gameObj.board();
    let whiteScore = 0;
    let blackScore = 0;
    for (let r = 0; r < 8; r++) {
      for (let c = 0; c < 8; c++) {
        const piece = currentBoard[r][c];
        if (piece) {
          const val = PIECE_VALUES[piece.type] || 0;
          if (piece.color === 'w') whiteScore += val;
          else blackScore += val;
        }
      }
    }
    setMaterialAdv(whiteScore - blackScore);
    setEvalValue((whiteScore - blackScore) * 0.8 + (Math.random() * 0.4 - 0.2)); 
  };

  useEffect(() => {
    const initGame = () => {
      if (typeof Chess !== 'undefined') {
        const newGame = new Chess();
        setGame(newGame);
        setBoard(newGame.board());
        setIsLibReady(true);
        runEvaluation(newGame);
      } else {
        setTimeout(initGame, 100);
      }
    };
    initGame();

    timerRef.current = setInterval(() => {
      setGame((current: any) => {
        if (!current || current.game_over()) return current;
        if (current.turn() === 'w') setWhiteTimer(t => Math.max(0, t - 1));
        else setBlackTimer(t => Math.max(0, t - 1));
        return current;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  const updateState = useCallback((gameObj: any) => {
    setBoard(gameObj.board());
    setHistory(gameObj.history());
    runEvaluation(gameObj);
    const turn = gameObj.turn() === 'w' ? '白方' : '黑方';
    if (gameObj.in_checkmate()) {
      setStatus(`将死！${turn === '白方' ? '黑方' : '白方'} 获胜`);
      setGameOver(true);
      playSound('checkmate');
    } else if (gameObj.in_draw()) {
      setStatus('平局！');
      setGameOver(true);
    } else {
      setStatus(`${turn}走棋`);
      if (gameObj.in_check()) playSound('check');
    }
  }, [playSound]);

  const makeAiMove = useCallback(() => {
    if (!game || game.game_over()) return;
    setIsAiThinking(true);
    setTimeout(() => {
      const moves = game.moves({ verbose: true });
      if (moves.length === 0) {
          setIsAiThinking(false);
          return;
      }
      const captures = moves.filter((m: any) => m.captured);
      const move = captures.length > 0 ? captures[Math.floor(Math.random() * captures.length)] : moves[Math.floor(Math.random() * moves.length)];
      const result = game.move(move.san);
      if (result) {
        setLastMove({ from: result.from, to: result.to });
        if (result.captured) {
            playSound('capture');
            setCaptured(prev => ({ ...prev, b: [...prev.b, result.captured] }));
        } else playSound('move');
      }
      updateState(game);
      setIsAiThinking(false);
    }, 600);
  }, [game, playSound, updateState]);

  const handleSquareClick = (row: number, col: number) => {
    if (gameOver || isAiThinking || !game) return;
    const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];
    const ranks = ['8', '7', '6', '5', '4', '3', '2', '1'];
    const square = files[col] + ranks[row];

    if (selectedSquare) {
      const result = game.move({ from: selectedSquare, to: square, promotion: 'q' });
      if (result) {
        setLastMove({ from: result.from, to: result.to });
        if (result.captured) {
            playSound('capture');
            setCaptured(prev => ({ ...prev, w: [...prev.w, result.captured] }));
        } else playSound('move');
        updateState(game);
        setSelectedSquare(null);
        setValidMoves([]);
        if (!game.game_over()) makeAiMove();
        return;
      }
    }

    const piece = game.get(square);
    if (piece && piece.color === game.turn()) {
      setSelectedSquare(square);
      const moves = game.moves({ square, verbose: true });
      setValidMoves(moves.map((m: any) => m.to));
    } else {
      setSelectedSquare(null);
      setValidMoves([]);
    }
  };

  const undoMove = () => {
    if (!game || gameOver || isAiThinking || history.length === 0) return;
    game.undo(); game.undo();
    updateState(game);
    setLastMove(null);
  };

  const resetGame = () => {
    const newGame = new Chess();
    setGame(newGame);
    setGameOver(false);
    setHistory([]);
    setLastMove(null);
    setWhiteTimer(600);
    setBlackTimer(600);
    setCaptured({ w: [], b: [] });
    updateState(newGame);
  };

  const formatTime = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (!isLibReady) {
      return (
          <div className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center">
              <Loader2 className="w-12 h-12 text-emerald-500 animate-spin mb-4" />
              <p className="text-white tech-font tracking-widest animate-pulse">BOOTING_LOGIC_CORE</p>
          </div>
      )
  }

  return (
    <div className="fixed inset-0 z-50 bg-[#020617] flex flex-col font-sans overflow-hidden">

      <div className="fixed top-0 left-0 w-full h-[3px] bg-slate-900 z-[100]">
          <div 
            className="h-full bg-emerald-400 transition-all duration-1000 ease-out shadow-[0_0_12px_rgba(52,211,153,0.8)]"
            style={{ width: `${Math.min(100, Math.max(0, 50 + evalValue * 10))}%` }}
          />
      </div>

      <header className="shrink-0 flex items-center justify-between px-4 pt-[calc(env(safe-area-inset-top)+12px)] pb-3 bg-slate-900/60 backdrop-blur-xl border-b border-white/5 z-20">
        <div className="bg-slate-950/80 px-4 py-2 rounded-full border border-white/10 flex items-center gap-3">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_#10b981]"></div>
          <span className="text-[10px] sm:text-xs font-black tech-font text-white uppercase italic tracking-tighter">{status}</span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setSoundEnabled(!soundEnabled)} className="p-2.5 bg-slate-800/80 text-white/60 hover:text-emerald-400 rounded-full border border-white/10 transition-all">
            {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
          </button>
          <button onClick={onClose} className="p-2.5 bg-slate-800/80 text-white/60 hover:text-red-500 rounded-full border border-white/10 transition-all">
            <X size={18}/>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col xl:flex-row items-center justify-center p-3 sm:p-6 lg:p-10 gap-4 xl:gap-12 relative overflow-y-auto no-scrollbar">

        <aside className="hidden xl:flex flex-col items-center gap-6 w-20">
            <div className="relative w-5 h-[450px] bg-slate-900 rounded-full overflow-hidden border border-white/10 shadow-inner">
                <div className="absolute bottom-0 w-full bg-gradient-to-t from-emerald-600 to-emerald-400 transition-all duration-1000" style={{ height: `${Math.min(98, Math.max(2, 50 + evalValue * 10))}%` }} />
            </div>
            <span className="text-[10px] font-black text-emerald-500 tech-font rotate-90 whitespace-nowrap opacity-50">EVAL_SENSORS</span>
        </aside>

        <div className="flex flex-col items-center w-full max-w-[min(100%,500px)] space-y-2 md:space-y-4">

            <div className="flex items-center justify-between w-full px-2 py-1 shrink-0">
                <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center border-2 transition-all duration-500 ${game?.turn() === 'b' ? 'bg-slate-800 border-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.3)]' : 'bg-slate-900 border-slate-800 text-slate-700'}`}>
                        <Cpu size={18} className={game?.turn() === 'b' ? 'text-emerald-400' : ''} />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[9px] font-black text-slate-500 uppercase leading-none mb-1 tracking-widest">AI_LOGIC_V4</span>
                        <div className="flex -space-x-1.5 opacity-60">
                            {captured.w.slice(-6).map((p, i) => (
                                <img key={i} src={PIECE_IMAGES[`w${p.toUpperCase()}`]} className="h-4 drop-shadow-sm" alt="cap" />
                            ))}
                        </div>
                    </div>
                </div>
                <div className={`text-lg md:text-xl font-black font-mono px-4 py-1.5 rounded-xl border-2 transition-all duration-500 ${game?.turn() === 'b' ? 'bg-emerald-500 border-emerald-400 text-black shadow-lg scale-105' : 'bg-slate-900/50 border-slate-800 text-slate-600'}`}>
                    {formatTime(blackTimer)}
                </div>
            </div>

            {/* 核心棋盘容器 - 优化平板适配 */}
            <div className="relative w-full aspect-square bg-[#2d1e15] p-1.5 rounded-xl shadow-[0_40px_100px_rgba(0,0,0,0.9)] border-[6px] border-[#3d2b1f] overflow-visible">
                <div className="absolute -left-6 top-0 bottom-0 flex flex-col justify-around text-[8px] font-black text-slate-700 italic pointer-events-none uppercase">
                    {['8','7','6','5','4','3','2','1'].map(n => <span key={n}>{n}</span>)}
                </div>
                <div className="absolute -bottom-6 left-0 right-0 flex justify-around text-[8px] font-black text-slate-700 italic pointer-events-none uppercase">
                    {['A','B','C','D','E','F','G','H'].map(l => <span key={l}>{l}</span>)}
                </div>

                <div className="grid grid-cols-8 grid-rows-8 w-full h-full border-2 border-slate-950 overflow-hidden rounded-md bg-slate-800">
                    {board.length > 0 && board.map((rowArr, r) => rowArr.map((cell, c) => {
                        const squareName = String.fromCharCode(97 + c) + (8 - r);
                        const isDark = (r + c) % 2 === 1;
                        const isSelected = selectedSquare === squareName;
                        const isValidTarget = validMoves.includes(squareName);
                        const isLast = lastMove && (lastMove.from === squareName || lastMove.to === squareName);
                        const isCheck = cell?.type === 'k' && cell?.color === game?.turn() && game?.in_check();

                        return (
                            <div 
                                key={`${r}-${c}`}
                                onClick={() => handleSquareClick(r, c)}
                                className="relative flex items-center justify-center cursor-pointer touch-manipulation transition-all duration-200 group"
                                style={{ backgroundColor: isDark ? THEMES[theme].dark : THEMES[theme].light }}
                            >
                                {isLast && <div className="absolute inset-0 bg-yellow-400/25 z-0" />}
                                {isSelected && <div className="absolute inset-0 bg-emerald-400/40 ring-inset ring-2 ring-emerald-400/30 z-0" />}
                                {isCheck && <div className="absolute inset-0 bg-red-600/40 animate-pulse z-0" />}

                                {isValidTarget && (
                                    <div className={`absolute w-3 h-3 md:w-4 md:h-4 rounded-full z-10 ${cell ? 'ring-4 ring-black/15' : 'bg-black/15 shadow-inner'}`} />
                                )}

                                {cell && (
                                    <img 
                                        src={PIECE_IMAGES[`${cell.color}${cell.type.toUpperCase()}`]} 
                                        alt={`${cell.color}${cell.type}`}
                                        loading="eager"
                                        className={`w-[90%] h-[90%] drop-shadow-[0_4px_4px_rgba(0,0,0,0.4)] transition-all duration-300 z-20 pointer-events-none group-active:scale-125 ${isSelected ? '-translate-y-2' : ''}`}
                                    />
                                )}
                            </div>
                        );
                    }))}
                </div>

                {isAiThinking && (
                    <div className="absolute inset-0 bg-black/10 backdrop-blur-[1px] flex items-center justify-center z-50 rounded-md">
                        <div className="bg-slate-950/95 px-5 py-3 rounded-2xl border border-emerald-500/40 flex items-center gap-3 animate-in zoom-in shadow-2xl">
                            <Cpu size={16} className="text-emerald-500 animate-spin" />
                            <span className="text-[10px] font-black tech-font text-emerald-500 uppercase italic tracking-[0.2em]">Synthesizing_Move</span>
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center justify-between w-full px-2 py-1 shrink-0">
                <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center border-2 transition-all duration-500 ${game?.turn() === 'w' ? 'bg-blue-600 border-blue-400 shadow-[0_0_20px_rgba(37,99,235,0.4)]' : 'bg-slate-900 border-slate-800 text-slate-700'}`}>
                        <User size={18} className={game?.turn() === 'w' ? 'text-white' : ''} />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[9px] font-black text-slate-500 uppercase leading-none mb-1 tracking-widest">COMMANDER</span>
                        <div className="flex -space-x-1.5 opacity-60">
                            {captured.b.slice(-6).map((p, i) => (
                                <img key={i} src={PIECE_IMAGES[`b${p.toUpperCase()}`]} className="h-4 drop-shadow-sm" alt="cap" />
                            ))}
                        </div>
                    </div>
                </div>
                <div className={`text-lg md:text-xl font-black font-mono px-4 py-1.5 rounded-xl border-2 transition-all duration-500 ${game?.turn() === 'w' ? 'bg-blue-600 border-blue-400 text-white shadow-lg scale-105' : 'bg-slate-900/50 border-slate-800 text-slate-600'}`}>
                    {formatTime(whiteTimer)}
                </div>
            </div>
        </div>

        <aside className="w-full xl:w-72 flex flex-col gap-3 self-stretch px-2 pb-6 max-w-[500px]">
            <div className="bg-slate-900/70 border border-white/5 p-4 rounded-2xl shadow-xl flex-1 flex flex-col overflow-hidden min-h-[100px] xl:min-h-0">
                <div className="flex items-center justify-between mb-3 border-b border-white/5 pb-2">
                    <h3 className="text-[10px] font-black text-emerald-400 uppercase tracking-widest flex items-center gap-2">
                        <History size={12} /> ENGAGEMENT_HISTORY
                    </h3>
                    <div className="text-[8px] font-mono text-slate-500 tracking-tighter">PHASE: {Math.ceil(history.length / 2)}</div>
                </div>

                <div className="flex-1 overflow-y-auto no-scrollbar grid grid-cols-4 xl:grid-cols-2 gap-2 content-start">
                    {history.map((move, i) => (
                        <div key={i} className={`flex items-center gap-2 text-[10px] p-2 rounded-lg bg-slate-950/80 border border-white/5 transition-all hover:border-emerald-500/30`}>
                            <span className="w-4 text-slate-600 text-right font-mono text-[8px]">{i % 2 === 0 ? Math.floor(i/2) + 1 + '.' : ''}</span>
                            <span className="font-bold text-slate-100 truncate">{move}</span>
                        </div>
                    ))}
                    {history.length === 0 && <p className="col-span-full text-[9px] text-slate-700 italic text-center py-6 uppercase tracking-[0.3em] font-black">Waiting_For_Initial_Move</p>}
                </div>
            </div>

            <div className="grid grid-cols-2 gap-3 shrink-0">
                <button onClick={undoMove} className="py-4 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-2xl font-black text-xs uppercase flex items-center justify-center gap-3 transition-all active:scale-95 border border-white/5 shadow-lg group">
                    <Undo2 size={16} className="group-hover:-rotate-45 transition-transform" /> UNDO
                </button>
                <button onClick={resetGame} className="py-4 bg-slate-800 hover:bg-red-500/20 text-slate-300 hover:text-red-400 rounded-2xl font-black text-xs uppercase flex items-center justify-center gap-3 transition-all active:scale-95 border border-white/5 shadow-lg">
                    <RotateCcw size={16} /> RESET
                </button>
            </div>
        </aside>
      </main>

      {gameOver && (
          <div className="fixed inset-0 z-[200] bg-slate-950/98 backdrop-blur-2xl flex flex-col items-center justify-center p-6 animate-in fade-in zoom-in duration-500 text-center">
              <div className="relative mb-8">
                <div className="absolute -inset-10 bg-emerald-500/20 rounded-full blur-3xl animate-pulse"></div>
                <Trophy size={100} className="text-emerald-400 relative z-10 drop-shadow-[0_0_40px_rgba(16,185,129,0.6)]" />
              </div>
              <h2 className="text-3xl md:text-5xl font-black text-white italic tech-font mb-2 uppercase tracking-tighter">Engagement_Concluded</h2>
              <p className="text-emerald-500 font-bold uppercase tracking-[0.4em] mb-12 text-sm md:text-base">{status}</p>
              <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md px-6">
                <button onClick={resetGame} className="flex-1 py-5 bg-white text-black font-black text-base rounded-[2rem] hover:bg-emerald-500 transition-all active:scale-95 tech-font uppercase shadow-2xl">New_Match</button>
                <button onClick={onClose} className="flex-1 py-5 bg-slate-900 text-white font-black text-base rounded-[2rem] hover:bg-slate-800 transition-all active:scale-95 tech-font uppercase border border-white/10 shadow-xl">Exit_Sync</button>
              </div>
          </div>
      )}

      <footer className="h-8 bg-slate-950 px-6 flex items-center justify-between z-20 shrink-0 border-t border-white/5">
        <div className="flex items-center gap-6">
            <span className="text-[8px] font-mono text-emerald-500/40 flex items-center gap-2 italic tracking-widest">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                NEURAL_LINK: ENCRYPTED
            </span>
            <span className="text-[8px] font-mono text-slate-800 uppercase tracking-widest italic hidden md:block">LATENCY: 14MS / CLUSTER_NODE_7</span>
        </div>
        <span className="text-[8px] font-mono text-slate-700 uppercase tracking-widest italic font-bold">V4.0_TABLET_OPTIMIZED</span>
      </footer>

      <style>{`
        .tech-font { font-family: 'Orbitron', sans-serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        @keyframes pulse-slow {
          0%, 100% { transform: scale(1); opacity: 1; }
          50% { transform: scale(0.98); opacity: 0.95; }
        }
        .animate-pulse-slow { animation: pulse-slow 3s infinite ease-in-out; }
      `}</style>
    </div>
  );
};

export default ChessApp;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Pencil, Eraser, PaintBucket, 
  Square, Circle, Undo2, Redo2, 
  Plus, Trash2, Save, Layers, Eye, EyeOff,
  Palette, Hand, Sliders, ChevronDown, 
  Minus, Maximize2, ZoomIn, ZoomOut, Info,
  MousePointer2
} from 'lucide-react';

type Tool = 'pencil' | 'eraser' | 'bucket' | 'line' | 'rect' | 'circle' | 'hand';

interface Layer {
  id: string;
  name: string;
  visible: boolean;
  canvas: HTMLCanvasElement;
}

const ProArtApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  // State
  const [layers, setLayers] = useState<Layer[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string>('');
  const [tool, setTool] = useState<Tool>('pencil');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1);
  const [color, setColor] = useState('#10b981');
  const [zoom, setZoom] = useState(1);
  const [panOffset, setPanOffset] = useState({ x: 0, y: 0 });
  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const [lastPos, setLastPos] = useState({ x: 0, y: 0 });
  const [mouseCanvasPos, setMouseCanvasPos] = useState({ x: 0, y: 0 });

  const viewportRef = useRef<HTMLDivElement>(null);
  const historyRef = useRef<string[][]>([]); 
  const historyIndexRef = useRef(-1);

  // Initialize
  useEffect(() => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const initialLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: '图层 1',
      visible: true,
      canvas: canvas,
    };
    setLayers([initialLayer]);
    setActiveLayerId(initialLayer.id);
    saveHistory([initialLayer]);
  }, []);

  const saveHistory = (currentLayers: Layer[]) => {
    const snapshots = currentLayers.map(l => l.canvas.toDataURL());
    const newHistory = historyRef.current.slice(0, historyIndexRef.current + 1);
    newHistory.push(snapshots);
    if (newHistory.length > 30) newHistory.shift();
    historyRef.current = newHistory;
    historyIndexRef.current = newHistory.length - 1;
  };

  const undo = () => {
    if (historyIndexRef.current <= 0) return;
    historyIndexRef.current--;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const redo = () => {
    if (historyIndexRef.current >= historyRef.current.length - 1) return;
    historyIndexRef.current++;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const applyHistoryState = (snapshots: string[]) => {
    const newLayers = layers.map((layer, i) => {
      const img = new Image();
      img.onload = () => {
        const ctx = layer.canvas.getContext('2d');
        if (ctx) {
          ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
          ctx.drawImage(img, 0, 0);
        }
      };
      img.src = snapshots[i];
      return layer;
    });
    setLayers([...newLayers]);
  };

  const addLayer = () => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const newLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: `图层 ${layers.length + 1}`,
      visible: true,
      canvas,
    };
    const nextLayers = [newLayer, ...layers];
    setLayers(nextLayers);
    setActiveLayerId(newLayer.id);
    saveHistory(nextLayers);
  };

  const removeLayer = (id: string) => {
    if (layers.length <= 1) return;
    const nextLayers = layers.filter(l => l.id !== id);
    setLayers(nextLayers);
    if (activeLayerId === id) setActiveLayerId(nextLayers[0].id);
    saveHistory(nextLayers);
  };

  const toggleLayerVisibility = (id: string) => {
    setLayers(layers.map(l => l.id === id ? { ...l, visible: !l.visible } : l));
  };

  const getCanvasPos = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = viewportRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    const x = (clientX - rect.left - (rect.width / 2) - panOffset.x + (1200 * zoom / 2)) / zoom;
    const y = (clientY - rect.top - (rect.height / 2) - panOffset.y + (800 * zoom / 2)) / zoom;

    return { x, y };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);

    if (tool === 'hand' || e.button === 1 || (e.button === 0 && e.altKey)) {
      setIsPanning(true);
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }

    setIsDrawing(true);
    setLastPos({ x, y });

    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;

    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;

    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.lineWidth = brushSize;
    ctx.globalAlpha = opacity;
    ctx.strokeStyle = color;
    ctx.fillStyle = color;

    if (tool === 'pencil') {
      ctx.beginPath();
      ctx.moveTo(x, y);
    } else if (tool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.beginPath();
      ctx.moveTo(x, y);
    } else if (tool === 'bucket') {
      floodFill(activeLayer.canvas, Math.floor(x), Math.floor(y), color);
      saveHistory(layers);
      setIsDrawing(false);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);
    setMouseCanvasPos({ x, y });

    if (isPanning) {
      const dx = e.clientX - lastPos.x;
      const dy = e.clientY - lastPos.y;
      setPanOffset(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }

    if (!isDrawing) return;

    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;
    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;

    if (tool === 'pencil' || tool === 'eraser') {
      ctx.lineTo(x, y);
      ctx.stroke();
    }
  };

  const handleMouseUp = () => {
    if (isDrawing) {
      const activeLayer = layers.find(l => l.id === activeLayerId);
      if (activeLayer) {
        const ctx = activeLayer.canvas.getContext('2d');
        if (ctx) {
          ctx.globalCompositeOperation = 'source-over';
        }
      }
      setIsDrawing(false);
      saveHistory(layers);
    }
    setIsPanning(false);
  };

  const floodFill = (canvas: HTMLCanvasElement, startX: number, startY: number, fillColor: string) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const pixels = imageData.data;
    const stack = [[startX, startY]];
    const startPos = (startY * canvas.width + startX) * 4;
    const startR = pixels[startPos];
    const startG = pixels[startPos + 1];
    const startB = pixels[startPos + 2];
    const startA = pixels[startPos + 3];
    const r = parseInt(fillColor.slice(1, 3), 16);
    const g = parseInt(fillColor.slice(3, 5), 16);
    const b = parseInt(fillColor.slice(5, 7), 16);
    if (startR === r && startG === g && startB === b && startA === 255) return;
    while (stack.length > 0) {
      const [x, y] = stack.pop()!;
      const pos = (y * canvas.width + x) * 4;
      if (x < 0 || x >= canvas.width || y < 0 || y >= canvas.height) continue;
      if (pixels[pos] !== startR || pixels[pos + 1] !== startG || pixels[pos + 2] !== startB || pixels[pos + 3] !== startA) continue;
      pixels[pos] = r; pixels[pos + 1] = g; pixels[pos + 2] = b; pixels[pos + 3] = 255;
      stack.push([x + 1, y], [x - 1, y], [x, y + 1], [x, y - 1]);
    }
    ctx.putImageData(imageData, 0, 0);
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#020617] flex flex-col font-sans text-slate-300 overflow-hidden select-none">

      {/* 顶部菜单栏 - 深度定制 */}
      <header className="h-14 bg-slate-900 border-b border-white/5 flex items-center justify-between px-6 shrink-0 shadow-xl z-20">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-[0_0_20px_rgba(16,185,129,0.3)] group-hover:scale-105 transition-transform">
              <Palette className="text-black w-6 h-6" />
            </div>
            <span className="text-lg font-black tech-font tracking-tighter uppercase italic text-white">ProArt_Web</span>
          </div>

          <div className="h-6 w-px bg-white/10" />

          <div className="flex items-center gap-2">
            <MenuButton icon={<Undo2 size={18} />} onClick={undo} title="撤销" />
            <MenuButton icon={<Redo2 size={18} />} onClick={redo} title="重做" />
          </div>

          <div className="h-6 w-px bg-white/10" />

          <div className="flex items-center gap-2">
             <MenuButton icon={<Save size={18} />} onClick={() => {}} title="保存到云端" className="text-emerald-400 hover:bg-emerald-500/10" />
             <MenuButton icon={<Trash2 size={18} />} onClick={() => {}} title="彻底清空" className="text-rose-400 hover:bg-rose-500/10" />
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="flex items-center gap-2 bg-slate-950/80 px-4 py-1.5 rounded-full border border-white/5 font-mono text-[10px] tracking-widest text-slate-500">
             <Maximize2 size={12} className="text-emerald-500" />
             ZOOM: <span className="text-white">{(zoom * 100).toFixed(0)}%</span>
           </div>
           <button onClick={onClose} className="p-2 bg-slate-800 hover:bg-rose-500 text-slate-400 hover:text-white rounded-full transition-all">
             <X size={20} />
           </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">

        {/* 左侧浮动工具栏 */}
        <aside className="w-16 bg-slate-900/90 backdrop-blur-xl border-r border-white/5 flex flex-col items-center py-6 gap-5 shadow-2xl relative z-20">
          <ToolButton icon={<Pencil size={22} />} active={tool === 'pencil'} onClick={() => setTool('pencil')} title="画笔 (B)" />
          <ToolButton icon={<Eraser size={22} />} active={tool === 'eraser'} onClick={() => setTool('eraser')} title="橡皮 (E)" />
          <ToolButton icon={<PaintBucket size={22} />} active={tool === 'bucket'} onClick={() => setTool('bucket')} title="填充 (G)" />
          <ToolButton icon={<Hand size={22} />} active={tool === 'hand'} onClick={() => setTool('hand')} title="抓手 (H/Space)" />

          <div className="w-10 h-px bg-white/5 my-2" />

          <ToolButton icon={<Square size={20} />} active={tool === 'rect'} onClick={() => {}} title="矩形工具" disabled />
          <ToolButton icon={<Circle size={20} />} active={tool === 'circle'} onClick={() => {}} title="圆形工具" disabled />

          <div className="mt-auto flex flex-col items-center gap-4 pb-4">
             <div className="w-10 h-10 rounded-xl border-2 border-white/10 p-0.5 shadow-lg overflow-hidden group cursor-pointer">
                <input 
                  type="color" 
                  value={color} 
                  onChange={(e) => setColor(e.target.value)} 
                  className="w-full h-full cursor-pointer bg-transparent border-none scale-150 group-hover:scale-125 transition-transform" 
                />
             </div>
          </div>
        </aside>

        {/* 中央主画布区域 */}
        <main 
          ref={viewportRef}
          className="flex-1 bg-[#080c14] relative overflow-hidden cursor-crosshair outline-none"
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          tabIndex={0}
          onWheel={(e) => {
            if (e.ctrlKey) {
              const delta = e.deltaY > 0 ? 0.9 : 1.1;
              setZoom(prev => Math.min(10, Math.max(0.1, prev * delta)));
              e.preventDefault();
            } else {
              setPanOffset(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
            }
          }}
        >
          {/* 画布环绕阴影 */}
          <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_100px_rgba(0,0,0,0.8)] z-10" />

          {/* 实际渲染画布 */}
          <div 
            className="absolute pointer-events-none"
            style={{ 
              width: 1200, height: 800,
              left: '50%', top: '50%',
              transform: `translate(-50%, -50%) translate(${panOffset.x}px, ${panOffset.y}px) scale(${zoom})`,
              boxShadow: '0 50px 100px -20px rgba(0,0,0,0.8), 0 30px 60px -30px rgba(0,0,0,0.9)'
            }}
          >
            {/* 棋盘格背景 */}
            <div className="absolute inset-0 bg-[#e5e5e5]" style={{ 
              backgroundImage: 'linear-gradient(45deg, #ccc 25%, transparent 25%), linear-gradient(-45deg, #ccc 25%, transparent 25%), linear-gradient(45deg, transparent 75%, #ccc 75%), linear-gradient(-45deg, transparent 75%, #ccc 75%)',
              backgroundSize: '20px 20px', backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px'
            }} />

            {/* 图层叠加 */}
            {[...layers].reverse().map((layer) => (
              <LayerCanvas key={layer.id} layer={layer} isActive={layer.id === activeLayerId} />
            ))}
          </div>

          {/* 实时状态指示器 */}
          <div className="absolute bottom-10 left-10 p-5 bg-slate-900/60 backdrop-blur-xl rounded-2xl border border-white/5 pointer-events-none flex flex-col gap-1 shadow-2xl animate-in slide-in-from-left-8 duration-700">
             <div className="flex items-center gap-3 text-[10px] font-black text-emerald-500 tech-font uppercase tracking-widest italic opacity-50">
               <Info size={12} /> Canvas_Sensor_Data
             </div>
             <div className="text-[12px] font-mono text-white/80 tracking-tighter">
                DIM: <span className="text-emerald-400">1200x800</span> | POS: <span className="text-emerald-400">{mouseCanvasPos.x.toFixed(0)}, {mouseCanvasPos.y.toFixed(0)}</span>
             </div>
             <div className="h-0.5 w-full bg-white/5 rounded-full mt-1 overflow-hidden">
                <div className="h-full bg-emerald-500/40" style={{ width: `${Math.min(100, zoom * 10)}%` }} />
             </div>
          </div>
        </main>

        {/* 右侧属性面板 */}
        <aside className="w-72 bg-slate-900 border-l border-white/5 flex flex-col overflow-hidden z-20 shadow-2xl">

          {/* 工具属性 */}
          <div className="p-6 border-b border-white/5">
             <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-emerald-500/10 rounded-lg">
                  <Sliders size={16} className="text-emerald-500" />
                </div>
                <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-white">工具属性</h3>
             </div>

             <div className="space-y-8">
                <div className="space-y-3">
                   <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                      <span className="uppercase tracking-widest">画笔大小</span>
                      <span className="bg-slate-950 px-2 py-0.5 rounded text-white font-mono">{brushSize}px</span>
                   </div>
                   <input 
                    type="range" min="1" max="100" value={brushSize} 
                    onChange={(e) => setBrushSize(parseInt(e.target.value))}
                    className="w-full h-1.5 bg-slate-950 rounded-full appearance-none accent-emerald-500 cursor-pointer" 
                   />
                </div>

                <div className="space-y-3">
                   <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                      <span className="uppercase tracking-widest">不透明度</span>
                      <span className="bg-slate-950 px-2 py-0.5 rounded text-white font-mono">{(opacity * 100).toFixed(0)}%</span>
                   </div>
                   <input 
                    type="range" min="0.01" max="1" step="0.01" value={opacity} 
                    onChange={(e) => setOpacity(parseFloat(e.target.value))}
                    className="w-full h-1.5 bg-slate-950 rounded-full appearance-none accent-emerald-500 cursor-pointer" 
                   />
                </div>
             </div>
          </div>

          {/* 图层管理 */}
          <div className="flex-1 flex flex-col min-h-0">
             <div className="p-6 border-b border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-emerald-500/10 rounded-lg">
                      <Layers size={16} className="text-emerald-500" />
                   </div>
                   <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-white">图层管理</h3>
                </div>
                <button onClick={addLayer} className="p-2 bg-slate-950 hover:bg-emerald-500 text-slate-400 hover:text-black rounded-lg transition-all shadow-inner">
                  <Plus size={16} />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                {layers.map((layer) => (
                  <div 
                    key={layer.id} 
                    onClick={() => setActiveLayerId(layer.id)}
                    className={`group flex items-center gap-4 px-4 py-3.5 rounded-2xl cursor-pointer transition-all border ${activeLayerId === layer.id ? 'bg-emerald-500/10 border-emerald-500/30 shadow-[inset_0_0_20px_rgba(16,185,129,0.05)]' : 'bg-slate-950/40 border-transparent hover:border-white/10'}`}
                  >
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleLayerVisibility(layer.id); }}
                      className={`transition-colors ${layer.visible ? 'text-emerald-500' : 'text-slate-700'}`}
                    >
                      {layer.visible ? <Eye size={18} /> : <EyeOff size={18} />}
                    </button>
                    <span className={`text-xs flex-1 truncate font-bold uppercase tracking-widest ${activeLayerId === layer.id ? 'text-white' : 'text-slate-500'}`}>
                      {layer.name}
                    </span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); removeLayer(layer.id); }}
                      className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-600 hover:text-rose-500 transition-all"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
             </div>
          </div>

          {/* 底部快速调色盘 */}
          <div className="p-6 bg-slate-950/50 border-t border-white/5">
             <div className="grid grid-cols-6 gap-2.5">
                {['#000000', '#ffffff', '#ff0000', '#00ff00', '#0000ff', '#ffff00', '#ff00ff', '#00ffff', '#ffa500', '#10b981', '#3b82f6', '#8b5cf6'].map(c => (
                  <button 
                    key={c} 
                    onClick={() => setColor(c)}
                    className={`aspect-square rounded-lg border border-white/5 hover:scale-110 transition-transform active:scale-95 ${color === c ? 'ring-2 ring-emerald-500 ring-offset-2 ring-offset-slate-950 scale-110' : ''}`}
                    style={{ backgroundColor: c }}
                  />
                ))}
             </div>
          </div>
        </aside>
      </div>

      <style>{`
        input[type="range"]::-webkit-slider-thumb {
          -webkit-appearance: none;
          width: 14px;
          height: 14px;
          background: #fff;
          border: 3px solid #10b981;
          border-radius: 50%;
          cursor: pointer;
          box-shadow: 0 0 10px rgba(16, 185, 129, 0.4);
        }
        .tech-font { font-family: 'Orbitron', sans-serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

// Sub-components
const MenuButton = ({ icon, onClick, title, className = '' }: any) => (
  <button 
    onClick={onClick} 
    title={title} 
    className={`p-2.5 bg-slate-800/50 hover:bg-slate-800 rounded-xl text-slate-400 hover:text-white transition-all shadow-sm active:scale-95 ${className}`}
  >
    {icon}
  </button>
);

const ToolButton = ({ icon, active, onClick, title, disabled = false }: any) => (
  <button 
    onClick={disabled ? undefined : onClick}
    title={title}
    className={`w-11 h-11 flex items-center justify-center rounded-xl transition-all relative ${disabled ? 'opacity-20 cursor-not-allowed' : active ? 'bg-emerald-500 text-black shadow-[0_0_25px_rgba(16,185,129,0.5)] scale-110' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800'}`}
  >
    {icon}
    {active && <div className="absolute -right-1 top-1/2 -translate-y-1/2 w-1 h-4 bg-white rounded-full animate-pulse" />}
  </button>
);

const LayerCanvas = React.memo(({ layer, isActive }: { layer: Layer, isActive: boolean }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d')!;
    const update = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(layer.canvas, 0, 0);
      requestAnimationFrame(update);
    };
    const id = requestAnimationFrame(update);
    return () => cancelAnimationFrame(id);
  }, [layer]);
  return (
    <canvas 
      ref={canvasRef} width={1200} height={800}
      className={`absolute inset-0 w-full h-full pointer-events-none transition-opacity duration-300 ${layer.visible ? 'opacity-100' : 'opacity-0'}`}
    />
  );
});

export default ProArtApp;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Pencil, Eraser, PaintBucket, 
  Undo2, Redo2, Plus, Trash2, Save, 
  Layers, Eye, EyeOff, Palette, Hand, 
  Sliders, ChevronRight, ChevronLeft,
  Maximize2, Info, LayoutPanelRight
} from 'lucide-react';

type Tool = 'pencil' | 'eraser' | 'bucket' | 'hand';

interface Layer {
  id: string;
  name: string;
  visible: boolean;
  canvas: HTMLCanvasElement;
}

const ProArtApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  // --- 状态管理 ---
  const [layers, setLayers] = useState<Layer[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string>('');
  const [tool, setTool] = useState<Tool>('pencil');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1);
  const [color, setColor] = useState('#10b981');
  const [zoom, setZoom] = useState(1);
  const [panOffset, setPanOffset] = useState({ x: 0, y: 0 });
  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const [lastPos, setLastPos] = useState({ x: 0, y: 0 });
  const [mouseCanvasPos, setMouseCanvasPos] = useState({ x: 0, y: 0 });
  const [showRightPanel, setShowRightPanel] = useState(true); // 控制右侧面板显隐

  const viewportRef = useRef<HTMLDivElement>(null);
  const historyRef = useRef<string[][]>([]); 
  const historyIndexRef = useRef(-1);

  // --- 初始化 ---
  useEffect(() => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const initialLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: '图层 1',
      visible: true,
      canvas: canvas,
    };
    setLayers([initialLayer]);
    setActiveLayerId(initialLayer.id);
    saveHistory([initialLayer]);
  }, []);

  const saveHistory = (currentLayers: Layer[]) => {
    const snapshots = currentLayers.map(l => l.canvas.toDataURL());
    const newHistory = historyRef.current.slice(0, historyIndexRef.current + 1);
    newHistory.push(snapshots);
    if (newHistory.length > 30) newHistory.shift();
    historyRef.current = newHistory;
    historyIndexRef.current = newHistory.length - 1;
  };

  const undo = () => {
    if (historyIndexRef.current <= 0) return;
    historyIndexRef.current--;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const redo = () => {
    if (historyIndexRef.current >= historyRef.current.length - 1) return;
    historyIndexRef.current++;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const applyHistoryState = (snapshots: string[]) => {
    const newLayers = layers.map((layer, i) => {
      const img = new Image();
      img.onload = () => {
        const ctx = layer.canvas.getContext('2d');
        if (ctx) {
          ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
          ctx.drawImage(img, 0, 0);
        }
      };
      img.src = snapshots[i];
      return layer;
    });
    setLayers([...newLayers]);
  };

  const addLayer = () => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const newLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: `图层 ${layers.length + 1}`,
      visible: true,
      canvas,
    };
    const nextLayers = [newLayer, ...layers];
    setLayers(nextLayers);
    setActiveLayerId(newLayer.id);
    saveHistory(nextLayers);
  };

  const removeLayer = (id: string) => {
    if (layers.length <= 1) return;
    const nextLayers = layers.filter(l => l.id !== id);
    setLayers(nextLayers);
    if (activeLayerId === id) setActiveLayerId(nextLayers[0].id);
    saveHistory(nextLayers);
  };

  const toggleLayerVisibility = (id: string) => {
    setLayers(layers.map(l => l.id === id ? { ...l, visible: !l.visible } : l));
  };

  const getCanvasPos = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = viewportRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    const x = (clientX - rect.left - (rect.width / 2) - panOffset.x + (1200 * zoom / 2)) / zoom;
    const y = (clientY - rect.top - (rect.height / 2) - panOffset.y + (800 * zoom / 2)) / zoom;

    return { x, y };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);
    if (tool === 'hand' || e.button === 1 || (e.button === 0 && e.altKey)) {
      setIsPanning(true);
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }
    setIsDrawing(true);
    setLastPos({ x, y });
    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;
    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;
    ctx.lineJoin = 'round'; ctx.lineCap = 'round';
    ctx.lineWidth = brushSize; ctx.globalAlpha = opacity;
    ctx.strokeStyle = color; ctx.fillStyle = color;
    if (tool === 'pencil') { ctx.beginPath(); ctx.moveTo(x, y); }
    else if (tool === 'eraser') { ctx.globalCompositeOperation = 'destination-out'; ctx.beginPath(); ctx.moveTo(x, y); }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);
    setMouseCanvasPos({ x, y });
    if (isPanning) {
      const dx = e.clientX - lastPos.x;
      const dy = e.clientY - lastPos.y;
      setPanOffset(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }
    if (!isDrawing) return;
    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;
    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;
    if (tool === 'pencil' || tool === 'eraser') { ctx.lineTo(x, y); ctx.stroke(); }
  };

  const handleMouseUp = () => {
    if (isDrawing) {
      const activeLayer = layers.find(l => l.id === activeLayerId);
      if (activeLayer) {
        const ctx = activeLayer.canvas.getContext('2d');
        if (ctx) ctx.globalCompositeOperation = 'source-over';
      }
      setIsDrawing(false);
      saveHistory(layers);
    }
    setIsPanning(false);
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#020617] flex flex-col font-sans text-slate-300 overflow-hidden select-none">

      {/* 顶部菜单栏 - 深度复刻设计稿 */}
      <header className="h-14 bg-slate-900 border-b border-white/5 flex items-center justify-between px-6 shrink-0 shadow-xl z-30">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-[0_0_20px_rgba(16,185,129,0.3)]">
              <Palette className="text-black w-6 h-6" />
            </div>
            <span className="text-lg font-black tech-font tracking-tighter uppercase italic text-white hidden sm:block">ProArt_Web</span>
          </div>

          <div className="h-6 w-px bg-white/10 mx-2" />

          <div className="flex items-center gap-1.5">
            <MenuButton icon={<Undo2 size={18} />} onClick={undo} title="撤销" />
            <MenuButton icon={<Redo2 size={18} />} onClick={redo} title="重做" />
          </div>

          <div className="h-6 w-px bg-white/10 mx-2 hidden md:block" />

          <div className="flex items-center gap-1.5">
             <MenuButton icon={<Save size={18} />} onClick={() => {}} title="保存" />
             <MenuButton icon={<Trash2 size={18} />} onClick={() => {}} title="彻底清空" className="text-rose-400" />
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2 bg-slate-950/80 px-4 py-1.5 rounded-lg border border-white/5 font-mono text-[10px] tracking-widest text-slate-500">
             ZOOM: <span className="text-white">{(zoom * 100).toFixed(0)}%</span>
           </div>
           <button 
             onClick={() => setShowRightPanel(!showRightPanel)}
             className={`p-2 rounded-lg transition-colors ${showRightPanel ? 'bg-emerald-500 text-black' : 'bg-slate-800 text-slate-400'}`}
             title="显示/隐藏属性面板"
           >
             <LayoutPanelRight size={20} />
           </button>
           <button onClick={onClose} className="p-2 bg-slate-800 hover:bg-rose-500 text-slate-400 hover:text-white rounded-lg transition-all">
             <X size={20} />
           </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">

        {/* 左侧工具栏 */}
        <aside className="w-16 bg-slate-900/90 backdrop-blur-xl border-r border-white/5 flex flex-col items-center py-6 gap-5 shadow-2xl relative z-20">
          <ToolButton icon={<Pencil size={22} />} active={tool === 'pencil'} onClick={() => setTool('pencil')} title="画笔" />
          <ToolButton icon={<Eraser size={22} />} active={tool === 'eraser'} onClick={() => setTool('eraser')} title="橡皮" />
          <ToolButton icon={<PaintBucket size={22} />} active={tool === 'bucket'} onClick={() => setTool('bucket')} title="油漆桶" />
          <ToolButton icon={<Hand size={22} />} active={tool === 'hand'} onClick={() => setTool('hand')} title="抓手" />

          <div className="w-10 h-px bg-white/5 my-2" />

          <div className="mt-auto flex flex-col items-center gap-4 pb-4">
             <div className="w-10 h-10 rounded-xl border-2 border-white/20 p-0.5 shadow-lg overflow-hidden group cursor-pointer relative">
                <input 
                  type="color" 
                  value={color} 
                  onChange={(e) => setColor(e.target.value)} 
                  className="absolute inset-0 w-full h-full cursor-pointer opacity-0 z-10" 
                />
                <div className="w-full h-full rounded-lg" style={{ backgroundColor: color }} />
             </div>
          </div>
        </aside>

        {/* 画布区域 */}
        <main 
          ref={viewportRef}
          className="flex-1 bg-[#080c14] relative overflow-hidden cursor-crosshair outline-none"
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          onWheel={(e) => {
            if (e.ctrlKey) {
              const delta = e.deltaY > 0 ? 0.9 : 1.1;
              setZoom(prev => Math.min(10, Math.max(0.1, prev * delta)));
              e.preventDefault();
            } else {
              setPanOffset(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
            }
          }}
        >
          {/* 画布容器 */}
          <div 
            className="absolute"
            style={{ 
              width: 1200, height: 800,
              left: '50%', top: '50%',
              transform: `translate(-50%, -50%) translate(${panOffset.x}px, ${panOffset.y}px) scale(${zoom})`,
              boxShadow: '0 40px 100px -20px rgba(0,0,0,0.8)'
            }}
          >
            {/* 棋盘格背景 */}
            <div className="absolute inset-0 bg-[#e5e5e5]" style={{ 
              backgroundImage: 'linear-gradient(45deg, #ccc 25%, transparent 25%), linear-gradient(-45deg, #ccc 25%, transparent 25%), linear-gradient(45deg, transparent 75%, #ccc 75%), linear-gradient(-45deg, transparent 75%, #ccc 75%)',
              backgroundSize: '20px 20px', backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px'
            }} />

            {/* 图层渲染 */}
            {[...layers].reverse().map((layer) => (
              <LayerCanvas key={layer.id} layer={layer} />
            ))}
          </div>

          {/* 实时状态指示器 (根据截图优化) */}
          <div className="absolute bottom-8 left-8 p-4 bg-slate-900/70 backdrop-blur-md rounded-xl border border-white/5 pointer-events-none flex flex-col gap-1 shadow-2xl">
             <div className="flex items-center gap-2 text-[9px] font-black text-slate-500 uppercase tracking-widest italic opacity-60 mb-1">
               <Info size={10} /> Telemetry_Output
             </div>
             <div className="text-[11px] font-mono text-white/80 whitespace-pre leading-relaxed">
                DIM: <span className="text-emerald-400">1200x800</span><br/>
                POS: <span className="text-emerald-400">{mouseCanvasPos.x.toFixed(0)}, {mouseCanvasPos.y.toFixed(0)}</span>
             </div>
          </div>
        </main>

        {/* 右侧属性面板 - 支持折叠 */}
        <aside 
          className={`bg-slate-900 border-l border-white/5 flex flex-col overflow-hidden z-20 shadow-2xl transition-all duration-500 ease-in-out ${showRightPanel ? 'w-72 opacity-100' : 'w-0 opacity-0'}`}
        >
          {/* 面板头部 */}
          <div className="p-6 border-b border-white/5 flex items-center justify-between">
             <div className="flex items-center gap-3">
                <Sliders size={16} className="text-emerald-500" />
                <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-white">工具属性</h3>
             </div>
             <button onClick={() => setShowRightPanel(false)} className="text-slate-600 hover:text-white transition-colors">
                <ChevronRight size={18} />
             </button>
          </div>

          <div className="p-6 space-y-8">
            {/* 画笔大小 */}
            <div className="space-y-3">
               <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                  <span className="uppercase tracking-widest">画笔大小</span>
                  <span className="text-emerald-400 font-mono">{brushSize}px</span>
               </div>
               <input 
                type="range" min="1" max="100" value={brushSize} 
                onChange={(e) => setBrushSize(parseInt(e.target.value))}
                className="custom-range" 
               />
            </div>

            {/* 不透明度 */}
            <div className="space-y-3">
               <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                  <span className="uppercase tracking-widest">不透明度</span>
                  <span className="text-emerald-400 font-mono">{(opacity * 100).toFixed(0)}%</span>
               </div>
               <input 
                type="range" min="0.01" max="1" step="0.01" value={opacity} 
                onChange={(e) => setOpacity(parseFloat(e.target.value))}
                className="custom-range" 
               />
            </div>
          </div>

          {/* 图层管理 */}
          <div className="flex-1 flex flex-col min-h-0">
             <div className="p-6 border-y border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <Layers size={16} className="text-emerald-500" />
                   <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-white">图层管理</h3>
                </div>
                <button onClick={addLayer} className="p-1.5 bg-slate-800 hover:bg-emerald-500 text-slate-400 hover:text-black rounded-lg transition-all">
                  <Plus size={16} />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
                {layers.map((layer) => (
                  <div 
                    key={layer.id} 
                    onClick={() => setActiveLayerId(layer.id)}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl cursor-pointer transition-all border ${activeLayerId === layer.id ? 'bg-emerald-500/10 border-emerald-500/40 shadow-[0_0_15px_rgba(16,185,129,0.1)]' : 'bg-slate-950/40 border-transparent hover:border-white/10'}`}
                  >
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleLayerVisibility(layer.id); }}
                      className={`transition-colors ${layer.visible ? 'text-emerald-500' : 'text-slate-700'}`}
                    >
                      {layer.visible ? <Eye size={18} /> : <EyeOff size={18} />}
                    </button>
                    <span className={`text-xs flex-1 truncate font-bold tracking-widest ${activeLayerId === layer.id ? 'text-white' : 'text-slate-500'}`}>
                      {layer.name}
                    </span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); removeLayer(layer.id); }}
                      className="p-1.5 text-slate-600 hover:text-rose-500"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
             </div>
          </div>

          {/* 快速调色盘 */}
          <div className="p-6 bg-slate-950/50 border-t border-white/5 grid grid-cols-6 gap-2">
            {['#000000', '#ffffff', '#ff0000', '#00ff00', '#0000ff', '#ffff00', '#ff00ff', '#10b981', '#3b82f6', '#8b5cf6', '#f43f5e', '#fbbf24'].map(c => (
              <button 
                key={c} onClick={() => setColor(c)}
                className={`aspect-square rounded-md border border-white/5 transition-transform hover:scale-110 ${color === c ? 'ring-2 ring-emerald-500 ring-offset-2 ring-offset-slate-950 scale-110' : ''}`}
                style={{ backgroundColor: c }}
              />
            ))}
          </div>
        </aside>

        {/* 隐藏面板时的唤醒按钮 */}
        {!showRightPanel && (
          <button 
            onClick={() => setShowRightPanel(true)}
            className="absolute right-0 top-1/2 -translate-y-1/2 bg-emerald-500 text-black py-4 px-1 rounded-l-xl z-20 shadow-2xl animate-pulse"
          >
            <ChevronLeft size={16} />
          </button>
        )}
      </div>

      <style>{`
        .custom-range {
          -webkit-appearance: none;
          width: 100%;
          height: 2px;
          background: #1e293b;
          border-radius: 5px;
          outline: none;
        }
        .custom-range::-webkit-slider-thumb {
          -webkit-appearance: none;
          width: 14px;
          height: 14px;
          background: #10b981;
          border-radius: 50%;
          cursor: pointer;
          box-shadow: 0 0 10px rgba(16,185,129,0.5);
          transition: transform 0.2s;
        }
        .custom-range::-webkit-slider-thumb:hover { transform: scale(1.2); }
        .tech-font { font-family: 'Orbitron', sans-serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

// 子组件
const MenuButton = ({ icon, onClick, title, className = '' }: any) => (
  <button 
    onClick={onClick} title={title} 
    className={`p-2.5 bg-slate-800/50 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-all active:scale-95 ${className}`}
  >
    {icon}
  </button>
);

const ToolButton = ({ icon, active, onClick, title }: any) => (
  <button 
    onClick={onClick} title={title}
    className={`w-11 h-11 flex items-center justify-center rounded-xl transition-all relative ${active ? 'bg-emerald-500 text-black shadow-[0_0_25px_rgba(16,185,129,0.4)]' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800'}`}
  >
    {icon}
    {active && <div className="absolute -right-1 top-1/2 -translate-y-1/2 w-1 h-3 bg-white rounded-full" />}
  </button>
);

const LayerCanvas = ({ layer }: { layer: Layer }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d')!;
    const update = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(layer.canvas, 0, 0);
      requestAnimationFrame(update);
    };
    const id = requestAnimationFrame(update);
    return () => cancelAnimationFrame(id);
  }, [layer]);
  return (
    <canvas 
      ref={canvasRef} width={1200} height={800}
      className={`absolute inset-0 w-full h-full pointer-events-none transition-opacity duration-300 ${layer.visible ? 'opacity-100' : 'opacity-0'}`}
    />
  );
};

export default ProArtApp;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Pencil, Eraser, PaintBucket, 
  Undo2, Redo2, Plus, Trash2, Save, 
  Layers, Eye, EyeOff, Palette, Hand, 
  Sliders, ChevronRight, ChevronLeft,
  Maximize2, Info, LayoutPanelRight
} from 'lucide-react';

type Tool = 'pencil' | 'eraser' | 'bucket' | 'hand';

interface Layer {
  id: string;
  name: string;
  visible: boolean;
  canvas: HTMLCanvasElement;
}

const ProArtApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  // --- 状态管理 ---
  const [layers, setLayers] = useState<Layer[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string>('');
  const [tool, setTool] = useState<Tool>('pencil');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1);
  const [color, setColor] = useState('#10b981');
  const [zoom, setZoom] = useState(1);
  const [panOffset, setPanOffset] = useState({ x: 0, y: 0 });
  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const [lastPos, setLastPos] = useState({ x: 0, y: 0 });
  const [mouseCanvasPos, setMouseCanvasPos] = useState({ x: 0, y: 0 });
  const [showRightPanel, setShowRightPanel] = useState(true); // 控制右侧面板显隐

  const viewportRef = useRef<HTMLDivElement>(null);
  const historyRef = useRef<string[][]>([]); 
  const historyIndexRef = useRef(-1);

  // --- 初始化 ---
  useEffect(() => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const initialLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: '图层 1',
      visible: true,
      canvas: canvas,
    };
    setLayers([initialLayer]);
    setActiveLayerId(initialLayer.id);
    saveHistory([initialLayer]);
  }, []);

  const saveHistory = (currentLayers: Layer[]) => {
    const snapshots = currentLayers.map(l => l.canvas.toDataURL());
    const newHistory = historyRef.current.slice(0, historyIndexRef.current + 1);
    newHistory.push(snapshots);
    if (newHistory.length > 30) newHistory.shift();
    historyRef.current = newHistory;
    historyIndexRef.current = newHistory.length - 1;
  };

  const undo = () => {
    if (historyIndexRef.current <= 0) return;
    historyIndexRef.current--;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const redo = () => {
    if (historyIndexRef.current >= historyRef.current.length - 1) return;
    historyIndexRef.current++;
    applyHistoryState(historyRef.current[historyIndexRef.current]);
  };

  const applyHistoryState = (snapshots: string[]) => {
    const newLayers = layers.map((layer, i) => {
      const img = new Image();
      img.onload = () => {
        const ctx = layer.canvas.getContext('2d');
        if (ctx) {
          ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
          ctx.drawImage(img, 0, 0);
        }
      };
      img.src = snapshots[i];
      return layer;
    });
    setLayers([...newLayers]);
  };

  const addLayer = () => {
    const canvas = document.createElement('canvas');
    canvas.width = 1200;
    canvas.height = 800;
    const newLayer: Layer = {
      id: Math.random().toString(36).substr(2, 9),
      name: `图层 ${layers.length + 1}`,
      visible: true,
      canvas,
    };
    const nextLayers = [newLayer, ...layers];
    setLayers(nextLayers);
    setActiveLayerId(newLayer.id);
    saveHistory(nextLayers);
  };

  const removeLayer = (id: string) => {
    if (layers.length <= 1) return;
    const nextLayers = layers.filter(l => l.id !== id);
    setLayers(nextLayers);
    if (activeLayerId === id) setActiveLayerId(nextLayers[0].id);
    saveHistory(nextLayers);
  };

  const toggleLayerVisibility = (id: string) => {
    setLayers(layers.map(l => l.id === id ? { ...l, visible: !l.visible } : l));
  };

  const getCanvasPos = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = viewportRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    const x = (clientX - rect.left - (rect.width / 2) - panOffset.x + (1200 * zoom / 2)) / zoom;
    const y = (clientY - rect.top - (rect.height / 2) - panOffset.y + (800 * zoom / 2)) / zoom;

    return { x, y };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);
    if (tool === 'hand' || e.button === 1 || (e.button === 0 && e.altKey)) {
      setIsPanning(true);
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }
    setIsDrawing(true);
    setLastPos({ x, y });
    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;
    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;
    ctx.lineJoin = 'round'; ctx.lineCap = 'round';
    ctx.lineWidth = brushSize; ctx.globalAlpha = opacity;
    ctx.strokeStyle = color; ctx.fillStyle = color;
    if (tool === 'pencil') { ctx.beginPath(); ctx.moveTo(x, y); }
    else if (tool === 'eraser') { ctx.globalCompositeOperation = 'destination-out'; ctx.beginPath(); ctx.moveTo(x, y); }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const { x, y } = getCanvasPos(e);
    setMouseCanvasPos({ x, y });
    if (isPanning) {
      const dx = e.clientX - lastPos.x;
      const dy = e.clientY - lastPos.y;
      setPanOffset(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastPos({ x: e.clientX, y: e.clientY });
      return;
    }
    if (!isDrawing) return;
    const activeLayer = layers.find(l => l.id === activeLayerId);
    if (!activeLayer) return;
    const ctx = activeLayer.canvas.getContext('2d');
    if (!ctx) return;
    if (tool === 'pencil' || tool === 'eraser') { ctx.lineTo(x, y); ctx.stroke(); }
  };

  const handleMouseUp = () => {
    if (isDrawing) {
      const activeLayer = layers.find(l => l.id === activeLayerId);
      if (activeLayer) {
        const ctx = activeLayer.canvas.getContext('2d');
        if (ctx) ctx.globalCompositeOperation = 'source-over';
      }
