        {/* 右侧属性面板 - 支持折叠 */}
        <aside 
          className={`bg-slate-900 border-l border-white/5 flex flex-col overflow-hidden z-20 shadow-2xl transition-all duration-500 ease-in-out ${showRightPanel ? 'w-72 opacity-100' : 'w-0 opacity-0'}`}
        >
