          <div className="p-6 bg-slate-950/50 border-t border-white/5 grid grid-cols-6 gap-2">
            {['#000000', '#ffffff', '#ff0000', '#00ff00', '#0000ff', '#ffff00', '#ff00ff', '#10b981', '#3b82f6', '#8b5cf6', '#f43f5e', '#fbbf24'].map(c => (
              <button 
